/// AboutLocalizations in `ar`.
class AboutLocalizationsAr extends AboutLocalizations {
  AboutLocalizationsAr([String locale = 'ar']) : super(locale);
  @override
  String get aboutCollapseContent => 'جمعية Trufi هي منظمة دولية غير حكومية تعمل على تسهيل الوصول إلى وسائل النقل العام. تساعد تطبيقاتنا الجميع على إيجاد أفضل طريقة للتنقل من النقطة أ إلى النقطة ب داخل مدنهم.\n\nفي العديد من المدن لا توجد خرائط أو مسارات أو تطبيقات أو جداول زمنية رسمية. لذلك نقوم بجمع المعلومات المتاحة، وأحيانًا نرسم المسارات من الصفر بالتعاون مع السكان المحليين الذين يعرفون المدينة. إن وجود نظام نقل سهل الاستخدام يسهم في تحقيق استدامة أكبر وهواء أنظف وجودة حياة أفضل.';
  @override
  String get aboutCollapseContentFoot => 'نحن بحاجة إلى راسمي خرائط ومطورين ومخططين ومختبرين والعديد من الأيادي الأخرى.';
  @override
  String get aboutCollapseTitle => 'المزيد عن جمعية Trufi';
  @override
  String get aboutLicenses => 'التراخيص';
  @override
  String get aboutOpenSource => 'تم إصدار هذا التطبيق كمصدر مفتوح على GitHub. لا تتردد في المساهمة في الكود، أو إطلاق تطبيق خاص بمدينتك.';
  @override
  String get menuAbout => 'من نحن';
  @override
  String get trufiWebsite => 'موقع جمعية Trufi';
  @override
  String get volunteerTrufi => 'تطوّع مع Trufi';
  @override
  String aboutContent(String appName, String city) => 'هل تحتاج إلى الذهاب إلى مكان ما ولا تعرف أي حافلة أو مسار تستقل؟\nتطبيق ${appName} يجعل الأمر سهلاً!\n\nجمعية Trufi هي فريق دولي من المتطوعين. نحن نحب وسائل النقل العام، ولهذا طوّرنا هذا التطبيق لتسهيل التنقل. هدفنا هو أن نوفر لك أداة عملية تتيح لك التنقل بثقة.\n\nنحن ملتزمون بالتحسين المستمر لتطبيق ${appName} لنقدم لك معلومات أكثر دقة وفائدة باستمرار. نعلم أن نظام النقل في ${city} يشهد تغييرات لأسباب مختلفة، لذا من المحتمل ألا تكون بعض المسارات محدثة بالكامل.\n\nلكي يكون ${appName} أداة فعّالة، نعتمد على تعاون مستخدمينا. إذا كنت على علم بتغييرات في بعض المسارات أو المحطات، فإننا نشجعك على مشاركة هذه المعلومات معنا. لن تساعد مساهمتك في إبقاء التطبيق محدثًا فحسب، بل ستفيد أيضًا المستخدمين الآخرين الذين يعتمدون على ${appName}.\n\nشكرًا لاختيارك ${appName} للتنقل في ${city}، نتمنى أن تستمتع بتجربتك معنا!';
  @override
  String tagline(String city) => 'النقل العام في ${city}';
  @override
  String version(String version) => 'الإصدار ${version}';
}

